import React from "react"
import Select from 'react-select'
import Calendar from 'react-select-date'
import { properties } from '../../properties/properties.js'



class CareWebPage extends React.Component {

    constructor(props) {
        super(props);
        this.state = {
            results: [], selectedDate: [], selectedSendTo: [], selectedTime: []
        };
    }


    handleSendChange = (selectedOptions) => {
      this.setState({selectedSendTo: selectedOptions})
    }

    handleTimeChange = (selectedOptions) => {
      this.setState({selectedTime: selectedOptions})
    }

    handleDateChange = (date) => {
      if (this.state.selectedDate !== date) {
        this.setState({selectedDate: date})
        //console.log(date);var myDate = new Date(date);console.log(myDate);
      }
    }


    handleSendPage = () => {
      console.log(document.getElementById("message").value)
      console.log(this.state.selectedSendTo)
      console.log(this.state.selectedTime)
      console.log(this.state.selectedDate)


      let headers = new Headers();

      headers.append('Content-Type', 'application/json');
      headers.append('Accept', 'application/json');


      var backUrl = properties.backend + `savepage`
      fetch(backUrl, {
        "method": "POST",
        headers: headers,
        body: JSON.stringify({evals: buildRequest})

      })
      .then(response => response.json())
      .then(response => {
        console.log(response);
        this.setState({createEvalResult: response})
        //this.setState({results: response})
        //this.setState({incompleteEval: response})
        //this.setState({stage: 1});
        //_forEach(response, d => console.log(d.name))
        //console.log(this.state.results)


        //var dateTeam = this.state.results.filter(Record => Record.eventDate === this.state.dateStr)[0].data.filter(Record => Record.id === this.state.teamId)[0]
        //this.callIncomplete(dateTeam);


        this.callRefreshData()

      })
      .catch(err => {
        console.log(err);
      });


    }

        componentDidMount() {


            /*
            const search = this.props.location.search;
            const params = new URLSearchParams(search);
            const programID = params.get('programid');

            var query = ""
            if (programID != null) {
              query = "?programid=" + programID 
            }

            let headers = new Headers();

            headers.append('Content-Type', 'application/json');
            headers.append('Accept', 'application/json');

            var backUrl = `http://localhost:9000/evalform`+query

            fetch(backUrl, {
                "method": "GET",
                headers: headers
              })
              .then(response => response.json())
              .then(response => {
                console.log(response);
                this.setState({results: response})
                //_forEach(response, d => console.log(d.name))
                //console.log(this.state.results)
              })
              .catch(err => {
                console.log(err);
              });
              */


          }

          render() {


            var header = "Loading ..."
            header = ""
            var content = []
            var rightContent = []
            var leftContent = []

            /*
            const options = [
              { value: 'chocolate', label: 'Chocolate' },
              { value: 'strawberry', label: 'Strawberry' },
              { value: 'vanilla', label: 'Vanilla' }
            ]
            */
           const options = [
             {value: '5930', label: 'Khanna, Raman'},
             {value: '1837', label: 'Sharpe, Bradley'},
             {value: '1850', label: 'Wu, Ethel'},
             {value: '3135', label: 'Shoeb, Marwa'},
             {value: '2470', label: 'Schaeffer, Sarah'},
             {value: '1889', label: 'Najafi, Nader'},
             {value: '6276', label: 'Lai, Andy'},
             {value: '6548', label: 'Auerbach, Andrew'}

           ]

           const cardiologyOptions = [
             {value: '6709', label: 'Rounding Team, Cardiology A'},
             {value: '6710', label: 'Rounding Team, Cardiology B'}, 
             {value: '6711', label: 'Rounding Team, Cardiology C'}, 
             {value: '6712', label: 'Rounding Team, Cardiology D'}
           ]


           const timeOptions = [
             {value: '6', label: '6:00 am'},
             {value: '12', label: '12:00 pm'}, 
             {value: '18', label: '6:00 pm'}, 
             {value: '24', label: '12:00 am'}
           ]



           const groupedOptions = [
             {label: 'Faculty', options: options},
             {label: 'Cardiology Team', options: cardiologyOptions}
           ]





           rightContent.push(<div style={{marginTop: "50px"}}>Send To:</div>)
           rightContent.push(<div style={{marginTop: "5px", display: "block"}}><Select

              isMulti
              name="sendTo"
              options={groupedOptions}
              className="basic-multi-select"
              classNamePrefix="select"
              onChange={this.handleSendChange}
            /></div>)


            rightContent.push(<div style={{marginTop: "15px"}}>Message:</div>)

            rightContent.push(<div style={{marginTop: "5px", display: "block"}}><textarea style={{width: "100%"}} id="message" name="message" rows="5"></textarea></div>)


            rightContent.push(<div style={{textAlign: "right", marginTop: "15px"}}><button onClick={() => this.handleSendPage()}  id="sendPage" style={{height: "40px", width: "120px", fontSize: "16px", backgroundColor: "yellow" }}>Send Page</button></div>)


          leftContent.push(<div>Date To Send:</div>)
          leftContent.push(<div style={{marginTop: "15px", display: "block"}}><Calendar
            onSelect={(date) => {this.handleDateChange(date);}}
            selectDateType="multiple"
            slotInfo={false}
            showDateInputField={false}
            //onSelect={this.handleDateChange}

          /></div>)
          leftContent.push(<div style={{marginTop: "15px"}}>Time To Send:</div>)
          leftContent.push(<div style={{marginTop: "5px", display: "block"}}><Select isMulti name="time" options={timeOptions} onChange={this.handleTimeChange}/></div>)



          content.push(<div style={{display: "flex"}}><div style={{marginRight: "50px"}}>{leftContent}</div><div style={{flex: "50%"}}>{rightContent}</div></div>)

            /*
            const search = this.props.location.search;
            const params = new URLSearchParams(search);
            const programID = params.get('programid');



            for (let x in this.state.results) {

                  //console.log(this.state.results[x])
                  todayDate = "programID: " + programID

                  var type = ""

                  for (let y in this.state.results[x].types) {
                    type += this.state.results[x].types[y] + "   "
                  }

                  var titleHtml = ""
                  titleHtml = <div style={{marginBottom: '10px'}}><u><b>{this.state.results[x].evaluation_title}</b></u> - {this.state.results[x].evaluationID} * {type}</div>
                  var introduction = ""
                  introduction = <div style={{marginLeft: '10px'}}><b>{this.state.results[x].introduction}</b></div>



                  content.push(titleHtml)
                  content.push(introduction)
                  content.push(<div><hr></hr></div>)
                  content.push(<div>&nbsp;</div>)

            }
*/




            return (
<div style={{minHeight: "500px", marginLeft: "50px", marginRight: "50px"}}><h2 className="display-4 text-center">{header}</h2>{content}</div>

            );
          }


  };

  export default CareWebPage
